# Day 239: Interview Prep: Project Walkthrough and HR Questions
# Project Walkthrough Template
walkthrough = {
    "situation": "Company losing 27% customers annually, costing $2M/year",
    "task": "Build predictive system to identify at-risk customers",
    "action": [
        "Cleaned 50K-row dataset with Pandas",
        "Engineered 15 features from raw data",
        "Trained 5 models, selected XGBoost (F1=0.83, AUC=0.91)",
        "Built FastAPI endpoint, Dockerized, deployed to AWS"
    ],
    "result": "Reduced churn by 15% in first quarter, saving ~$300K"
}

print("Project Walkthrough (STAR):")
for key, val in walkthrough.items():
    print(f"\n{key.upper()}:")
    if isinstance(val, list):
        for item in val:
            print(f"  • {item}")
    else:
        print(f"  {val}")
